function calculate(inputs) {
  const expectedSnowfallInches = inputs.expectedSnowfallInches;
  const propertyLotSizeSqFt = inputs.propertyLotSizeSqFt;
  const drivewayLengthFeet = inputs.drivewayLengthFeet;
  const sidewalkLengthFeet = inputs.sidewalkLengthFeet;
  const hasExistingSnowBlower = inputs.hasExistingSnowBlower;
  const roofPitchCategory = inputs.roofPitchCategory;
  const professionalPlowingPreference = inputs.professionalPlowingPreference;
  const treeDensityOnProperty = inputs.treeDensityOnProperty;
  const hourlyLaborCost = inputs.hourlyLaborCost;

  // Constants for average costs and efficiency
  const basicShovelCost = 30;
  const saltCostPerSqFtPerInch = 0.005;
  const entryLevelSnowBlowerCost = 500; // Small driveways, light snow
  const midRangeSnowBlowerCost = 1000;  // Medium driveways, moderate snow
  const roofRakeCost = 70;
  const proPlowingPerVisitSmallDrive = 75;
  const proPlowingPerVisitMediumDrive = 120;
  const proPlowingPerVisitLargeDrive = 180;
  const proRoofSnowRemovalRatePerSqFt = 0.75; // Higher rate for professional roof work
  const baseTreeDamageRiskCostLow = 50;
  const baseTreeDamageRiskCostMedium = 200;
  const baseTreeDamageRiskCostHigh = 500;
  const treeDamageMultiplierPerInchSnow = 15;
  const avgPropertyAreaPerPersonHourShovel = 500; // sq ft per hour for manual shoveling pathways
  const avgDrivewayLengthPerPersonHourShovel = 100; // feet per hour for manual shoveling
  const avgSidewalkLengthPerPersonHourShovel = 200; // feet per hour for manual shoveling
  const avgPropertyAreaPerPersonHourSnowBlower = 2000; // sq ft per hour for snow blower pathways
  const avgDrivewayLengthPerPersonHourSnowBlower = 500; // feet per hour for snow blower
  const avgSidewalkLengthPerPersonHourSnowBlower = 800; // feet per hour for snow blower
  const roofSqFtPerLotSqFtFactor = 0.4; // Average roof footprint vs lot size

  let suppliesCost = 0;
  let equipmentCost = 0;
  let laborCost = 0;
  let potentialRepairCost = 0;
  let totalEstimatedTimeHours = 0;

  // 1. Supplies Cost
  // Base cost for essentials (e.g., gloves, emergency items if not already owned)
  suppliesCost += basicShovelCost; // Assume at least one shovel or replacement needed

  // Salt/Ice Melt based on paved areas and expected snowfall
  const saltableArea = (drivewayLengthFeet * 10) + (sidewalkLengthFeet * 5) + (propertyLotSizeSqFt * 0.05); // Driveway width ~10ft, sidewalk ~5ft, plus entry paths
  suppliesCost += expectedSnowfallInches * saltCostPerSqFtPerInch * saltableArea;
  suppliesCost = Math.min(suppliesCost, 500); // Cap supplies cost

  // 2. Equipment Cost
  if (hasExistingSnowBlower === "No") {
    if (expectedSnowfallInches >= 8 && (drivewayLengthFeet > 75 || propertyLotSizeSqFt > 7500)) {
      equipmentCost += midRangeSnowBlowerCost;
    } else if (expectedSnowfallInches >= 4 && (drivewayLengthFeet > 25 || propertyLotSizeSqFt > 2500)) {
      equipmentCost += entryLevelSnowBlowerCost;
    }
  }
  if (roofPitchCategory === "Low Pitch / Flat" && expectedSnowfallInches >= 8) {
    equipmentCost += roofRakeCost;
  }

  // 3. Labor Cost & Time
  const estimatedShovelablePropertyArea = propertyLotSizeSqFt * 0.05; // Paths, entryways on property
  const estimatedRoofAreaSqFt = propertyLotSizeSqFt * roofSqFtPerLotSqFtFactor;
  let DIYHours = 0;

  // Plowing/Snow Removal (Driveway & Sidewalks)
  let snowRemovalHoursPerEvent;
  if (hasExistingSnowBlower === "Yes") {
    snowRemovalHoursPerEvent = 
      (estimatedShovelablePropertyArea / avgPropertyAreaPerPersonHourSnowBlower) +
      (drivewayLengthFeet / avgDrivewayLengthPerPersonHourSnowBlower) +
      (sidewalkLengthFeet / avgSidewalkLengthPerPersonHourSnowBlower);
  } else {
    snowRemovalHoursPerEvent = 
      (estimatedShovelablePropertyArea / avgPropertyAreaPerPersonHourShovel) +
      (drivewayLengthFeet / avgDrivewayLengthPerPersonHourShovel) +
      (sidewalkLengthFeet / avgSidewalkLengthPerPersonHourShovel);
  }
  snowRemovalHoursPerEvent = Math.max(0.5, snowRemovalHoursPerEvent); // Minimum 30 mins even for small jobs

  if (professionalPlowingPreference === "Professional Services Only") {
    const numPlowEvents = Math.max(2, Math.floor(expectedSnowfallInches / 5)); // Assume a plow for every 5-8 inches
    let plowCostPerVisit = proPlowingPerVisitSmallDrive;
    if (drivewayLengthFeet > 100 || propertyLotSizeSqFt > 15000) {
      plowCostPerVisit = proPlowingPerVisitLargeDrive;
    } else if (drivewayLengthFeet > 50 || propertyLotSizeSqFt > 7500) {
      plowCostPerVisit = proPlowingPerVisitMediumDrive;
    }
    laborCost += numPlowEvents * plowCostPerVisit;
    DIYHours += numPlowEvents * 0.5; // Still some minor DIY cleanup even with pros

  } else if (professionalPlowingPreference === "Hybrid (DIY + Pro Support)") {
    const numProPlowEvents = Math.max(1, Math.floor(expectedSnowfallInches / 10)); // Fewer events for professional
    let plowCostPerVisit = proPlowingPerVisitSmallDrive;
    if (drivewayLengthFeet > 100 || propertyLotSizeSqFt > 15000) {
      plowCostPerVisit = proPlowingPerVisitLargeDrive;
    } else if (drivewayLengthFeet > 50 || propertyLotSizeSqFt > 7500) {
      plowCostPerVisit = proPlowingPerVisitMediumDrive;
    }
    laborCost += numProPlowEvents * plowCostPerVisit;

    const remainingDIYSnowfallEvents = Math.max(0, Math.floor((expectedSnowfallInches - (numProPlowEvents * 6)) / 3)); // Remaining snowfall broken into DIY events (e.g., every 3 inches)
    DIYHours += remainingDIYSnowfallEvents * snowRemovalHoursPerEvent;

  } else { // DIY Primarily
    const numDIYSnowfallEvents = Math.max(1, Math.floor(expectedSnowfallInches / 3)); // Assume DIY for every 3-inch increment
    DIYHours += numDIYSnowfallEvents * snowRemovalHoursPerEvent;
  }

  // Roof Snow Removal
  if (roofPitchCategory === "Low Pitch / Flat" && expectedSnowfallInches >= 12) {
    const roofRemovalHours = estimatedRoofAreaSqFt / 250; // Manual roof raking efficiency
    if (professionalPlowingPreference !== "DIY Primarily") {
      laborCost += estimatedRoofAreaSqFt * proRoofSnowRemovalRatePerSqFt; // Professional roof removal
      DIYHours += roofRemovalHours * 0.2; // Some minor DIY oversight
    } else {
      DIYHours += roofRemovalHours;
    }
  }

  // Cap DIY hours to prevent extreme values
  DIYHours = Math.min(DIYHours, 100); // Maximum reasonable DIY effort for a single storm
  totalEstimatedTimeHours = DIYHours; // Assign DIY hours to total estimated time
  laborCost += DIYHours * hourlyLaborCost;

  // 4. Potential Repair Cost
  let baseRisk = 0;
  if (treeDensityOnProperty === "Low") { baseRisk = baseTreeDamageRiskCostLow; }
  else if (treeDensityOnProperty === "Medium") { baseRisk = baseTreeDamageRiskCostMedium; }
  else { baseRisk = baseTreeDamageRiskCostHigh; }

  potentialRepairCost = baseRisk + 
    (expectedSnowfallInches / 6) * treeDamageMultiplierPerInchSnow * 
    (treeDensityOnProperty === "High" ? 1.5 : (treeDensityOnProperty === "Medium" ? 1.0 : 0.5));

  // Add a small baseline for ice dam potential if conditions are right
  if (expectedSnowfallInches > 8 && roofPitchCategory === "Low Pitch / Flat") {
    potentialRepairCost += 150; // Average cost for minor ice dam mitigation/repair
  }

  // 5. Total Estimated Cost
  const totalEstimatedCost = suppliesCost + equipmentCost + laborCost + potentialRepairCost;

  return {
    totalEstimatedCost: parseFloat(totalEstimatedCost.toFixed(2)),
    totalEstimatedTimeHours: parseFloat(totalEstimatedTimeHours.toFixed(1)),
    suppliesCost: parseFloat(suppliesCost.toFixed(2)),
    equipmentCost: parseFloat(equipmentCost.toFixed(2)),
    laborCost: parseFloat(laborCost.toFixed(2)),
    potentialRepairCost: parseFloat(potentialRepairCost.toFixed(2))
  };
}
